import React from "react";

const Navbar = () => {
  const scrollToSection = (id) => {
    const element = document.getElementById(id);
    if (element) {
      element.scrollIntoView({ behavior: "smooth" });
    }
  };

  return (
    <nav
      style={{
        display: "flex",
        justifyContent: "space-between",
        alignItems: "center",
        padding: "1rem 2rem",
        backgroundColor: "#FF4C29",
        color: "#fff",
        position: "sticky",
        top: 0,
        zIndex: 1000,
      }}
    >
      {/* Logo as a button */}
      <button
        onClick={() => scrollToSection("home")}
        style={{
          fontWeight: "bold",
          fontSize: "1.2rem",
          background: "none",
          border: "none",
          color: "#fff",
          cursor: "pointer",
        }}
      >
        Sindhuja Kannuri
      </button>

      {/* Buttons for navigation */}
      <div style={{ display: "flex", gap: "1rem" }}>
        <button
          onClick={() => scrollToSection("home")}
          style={buttonStyle}
        >
          Home
        </button>
        <button
          onClick={() => scrollToSection("about")}
          style={buttonStyle}
        >
          About
        </button>
        <button
          onClick={() => scrollToSection("projects")}
          style={buttonStyle}
        >
          Projects
        </button>
        <button
          onClick={() => scrollToSection("contact")}
          style={buttonStyle}
        >
          Contact
        </button>
      </div>
    </nav>
  );
};

// Common button style
const buttonStyle = {
  background: "none",
  border: "1px solid #fff",
  borderRadius: "5px",
  padding: "0.4rem 0.8rem",
  color: "#fff",
  cursor: "pointer",
  fontSize: "0.9rem",
  transition: "0.2s",
};

export default Navbar;
